import { useEffect, useState } from "react";
import API from "../api/axios";
import { useNavigate } from "react-router-dom";
import {
  PieChart,
  Pie,
  Cell,
  Tooltip,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Legend
} from "recharts";

function Dashboard() {

    const navigate = useNavigate();

  const [data, setData] = useState(null);


  useEffect(() => {
    const fetchDashboard = async () => {
      try {
        const res = await API.get("/dashboard");
        setData(res.data);
      } catch (error) {
        console.log(error);
      }
    };

    fetchDashboard();
  }, []);

  if (!data) return <h2>Loading...</h2>;

  // Pie Chart Data
  const pieData = [
    { name: "Income", value: data.totalIncome },
    { name: "Expense", value: data.totalExpense }
  ];

  const COLORS = ["#28a745", "#dc3545"];

  // Bar Chart Data (Monthly)
  const barData = data.monthlyData.map(item => ({
    month: `Month ${item._id.month}`,
    total: item.total
  }));

  return (
    <div style={{ padding: "20px" }}>
      <h2>Dashboard</h2>

      {/* Cards */}
      <div style={{ display: "flex", gap: "20px", marginTop: "20px" }}>
        <div style={cardStyle}>
          <h3>Balance</h3>
          <p>₹ {data.balance}</p>
        </div>

        <div style={{ ...cardStyle, backgroundColor: "#d4edda" }}>
          <h3>Income</h3>
          <p>₹ {data.totalIncome}</p>
        </div>

        <div style={{ ...cardStyle, backgroundColor: "#f8d7da" }}>
          <h3>Expense</h3>
          <p>₹ {data.totalExpense}</p>
        </div>
      </div>

      {/* Charts Section */}
      <div style={{ display: "flex", gap: "50px", marginTop: "40px" }}>

        {/* Pie Chart */}
        <div>
          <h3>Income vs Expense</h3>
          <PieChart width={300} height={300}>
            <Pie
              data={pieData}
              cx="50%"
              cy="50%"
              outerRadius={100}
              dataKey="value"
              label
            >
              {pieData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={COLORS[index]} />
              ))}
            </Pie>
            <Tooltip />
          </PieChart>
        </div>

        {/* Bar Chart */}
        <div>
          <h3>Monthly Expenses</h3>
          <BarChart width={400} height={300} data={barData}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="month" />
            <YAxis />
            <Tooltip />
            <Legend />
            <Bar dataKey="total" fill="#007bff" />
          </BarChart>
        </div>

      </div>
    </div>
  );
}

const cardStyle = {
  flex: 1,
  padding: "20px",
  borderRadius: "10px",
  backgroundColor: "#e2e3e5",
  textAlign: "center",
  boxShadow: "0 2px 8px rgba(0,0,0,0.1)"
};

export default Dashboard;
